diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..9ac162f65599 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1586,6 +1586,57 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   WithCache<const Value *> LHSCache(LHS), RHSCache(RHS);
   if (haveNoCommonBitsSet(LHSCache, RHSCache, SQ.getWithInstruction(&I)))
     return BinaryOperator::CreateDisjointOr(LHS, RHS);
+  // add (mul/shl ({u,s}div X, C0), C1), ({u,s}rem X, C0) -->
+  // add (mul ({u,s}div X, C0), (C1 - C0)), X
+  {
+    Value *X;
+    const APInt *C0;
+    for (int i = 0; i < 2; ++i) {
+      Value *A = I.getOperand(i);
+      Value *B = I.getOperand(1 - i);
+      if (!A->hasOneUse())
+        continue;
+      // B should be (urem/srem X, C0)
+      bool IsSigned;
+      if (match(B, m_OneUse(m_URem(m_Value(X), m_APInt(C0)))))
+        IsSigned = false;
+      else if (match(B, m_OneUse(m_SRem(m_Value(X), m_APInt(C0)))))
+        IsSigned = true;
+      else
+        continue;
+      // A should be (mul/shl ({u,s}div X, C0), C1)
+      Value *Div;
+      const APInt *MulC;
+      const APInt *ShiftC;
+      APInt MulVal(Ty->getScalarSizeInBits(), 0);
+      bool Matched = false;
+      if (match(A, m_Mul(m_Value(Div), m_APInt(MulC)))) {
+        MulVal = *MulC;
+        Matched = true;
+      } else if (match(A, m_Shl(m_Value(Div), m_APInt(ShiftC)))) {
+        if (ShiftC->ult(Ty->getScalarSizeInBits())) {
+          MulVal = APInt(Ty->getScalarSizeInBits(), 1) << *ShiftC;
+          Matched = true;
+        }
+      }
+      if (!Matched)
+        continue;
+      if (IsSigned) {
+        if (!match(Div, m_SDiv(m_Specific(X), m_SpecificInt(*C0))))
+          continue;
+      } else {
+        if (!match(Div, m_UDiv(m_Specific(X), m_SpecificInt(*C0))))
+          continue;
+      }
+      APInt Diff = MulVal - *C0;
+      if (Diff == 0)
+        return replaceInstUsesWith(I, X);
+      Value *NewMul = Builder.CreateMul(Div, ConstantInt::get(Ty, Diff),
+                                        "", /*HasNUW*/ !IsSigned,
+                                        /*HasNSW*/ IsSigned);
+      return BinaryOperator::CreateAdd(NewMul, X);
+    }
+  }

   if (Instruction *Ext = narrowMathIfNoOverflow(I))
     return Ext;
